// These constants represent the RISC-V ELF and the image ID generated by risc0-build.
// The ELF is used for proving and the ID is used for verification.
use methods::{KINCADECORE_GUEST_ELF, KINCADECORE_GUEST_ID};
use risc0_zkvm::{default_prover, ExecutorEnv};
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
struct KincadeCoreReadout {
    summary: String,
    complete: bool,
    partial_call: bool,
    ok_count: u32,
    records_read: u32,
    atoms_found: u32,
    edges_created: u32,
    cycles_found: u32,
    solver_outputs: u32,
    physics_outputs: u32,
    records_written: u32,
    stabilizer_converged: bool,
    stabilizer_converged_at: u32,
    stabilizer_k_scaled: u64,
    stabilizer_contraction_rate_scaled: u64,
    stabilizer_rate_match: bool,
    seal: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct KincadeCoreJournal {
    complete: bool,
    partial_call: bool,
    ok_count: u32,
    records_read: u32,
    atoms_found: u32,
    edges_created: u32,
    cycles_found: u32,
    solver_outputs: u32,
    physics_outputs: u32,
    records_written: u32,
    stabilizer_converged: bool,
    stabilizer_rate_match: bool,
    seal: String,
}

fn main() {
    tracing_subscriber::fmt()
        .with_env_filter(tracing_subscriber::filter::EnvFilter::from_default_env())
        .init();

    let readout = KincadeCoreReadout {
        summary: "KincadeCore completed the solve/readout path.".to_string(),
        complete: true,
        partial_call: false,
        ok_count: 36,
        records_read: 10,
        atoms_found: 90,
        edges_created: 72,
        cycles_found: 10,
        solver_outputs: 80,
        physics_outputs: 10,
        records_written: 90,
        stabilizer_converged: true,
        stabilizer_converged_at: 25,
        stabilizer_k_scaled: 693_147_180_559_945,
        stabilizer_contraction_rate_scaled: 306_852_819_440_054,
        stabilizer_rate_match: true,
        seal: "00aba5cb6bc00496c0482eb0fe7ee210caae937c1658c67a117d87c97cd14617".to_string(),
    };

    let env = ExecutorEnv::builder()
        .write(&readout)
        .unwrap()
        .build()
        .unwrap();

    let prover = default_prover();

    let prove_info = prover
        .prove(env, KINCADECORE_GUEST_ELF)
        .unwrap();

    let receipt = prove_info.receipt;

    let journal: KincadeCoreJournal = receipt.journal.decode().unwrap();

    assert!(journal.complete);
    assert!(!journal.partial_call);
    assert_eq!(journal.ok_count, 36);
    assert_eq!(journal.records_read, 10);
    assert_eq!(journal.atoms_found, 90);
    assert_eq!(journal.edges_created, 72);
    assert_eq!(journal.cycles_found, 10);
    assert_eq!(journal.solver_outputs, 80);
    assert_eq!(journal.physics_outputs, 10);
    assert_eq!(journal.records_written, 90);
    assert!(journal.stabilizer_converged);
    assert!(journal.stabilizer_rate_match);
    assert_eq!(
        journal.seal,
        "00aba5cb6bc00496c0482eb0fe7ee210caae937c1658c67a117d87c97cd14617"
    );

    receipt.verify(KINCADECORE_GUEST_ID).unwrap();

    println!("KincadeCore RISC Zero proof verified.");
    println!("complete={}", journal.complete);
    println!("ok_count={}", journal.ok_count);
    println!("records_read={}", journal.records_read);
    println!("atoms_found={}", journal.atoms_found);
    println!("edges_created={}", journal.edges_created);
    println!("cycles_found={}", journal.cycles_found);
    println!("solver_outputs={}", journal.solver_outputs);
    println!("physics_outputs={}", journal.physics_outputs);
    println!("records_written={}", journal.records_written);
    println!("stabilizer_converged={}", journal.stabilizer_converged);
    println!("stabilizer_rate_match={}", journal.stabilizer_rate_match);
    println!("seal={}", journal.seal);
}
